mapper.select:
SELECT u.id, u.email, u.phone, u.nickname, u.status, u.register_source AS registerSource, u.role, up.study_stage AS studyStage, u.last_active_at AS lastActiveAt, u.created_at AS createdAt, GROUP_CONCAT(aur.role ORDER BY aur.role SEPARATOR ',') AS adminRolesCsv FROM users u LEFT JOIN user_profile up ON up.user_id = u.id LEFT JOIN admin_user_role aur ON aur.user_id = u.id WHERE 1 = 1
AND ( u.email LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') )
AND u.status = #{status} AND u.register_source = #{registerSource} AND up.study_stage = #{studyStage} AND u.last_active_at >= #{lastActiveFrom} AND u.last_active_at <= #{lastActiveTo} AND aur.role = #{adminRole} GROUP BY u.id, u.email, u.phone, u.nickname, u.status, u.register_source, u.role, up.study_stage, u.last_active_at, u.created_at ORDER BY u.created_at DESC, u.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(DISTINCT u.id)
FROM users u
LEFT JOIN user_profile up ON up.user_id = u.id
LEFT JOIN admin_user_role aur ON aur.user_id = u.id
WHERE 1 = 1

    AND (
      u.email LIKE CONCAT('%', #{keyword}, '%')
      OR u.phone LIKE CONCAT('%', #{keyword}, '%')
      OR u.nickname LIKE CONCAT('%', #{keyword}, '%')
    )

  AND u.status = #{status}
  AND u.register_source = #{registerSource}
  AND up.study_stage = #{studyStage}
  AND u.last_active_at >= #{lastActiveFrom}
  AND u.last_active_at <= #{lastActiveTo}
  AND aur.role = #{adminRole}
